const Q_IRK_2011=[{"id": "objective>IRK>2011>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The outcome of the Prophet's visit to Cave Hira was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">compilation of the Glorious Qur'an</div>", "<div style=\"font-family:Cambria;font-size:17px;\">revelation of the Glorious Qur'an</div>", "<div style=\"font-family:Cambria;font-size:17px;\">award of chieftaincy title by the Makkan aristocrats</div>", "<div style=\"font-family:Cambria;font-size:17px;\">his resolve to migrate to Madinah</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When the prophet was about 40 years of age, he usually visit care Hirah to withdraw himself from vices in the community . At age 40, Angel Jubril appeared to him and gave him the revelation of Quran.</div>", "topic": "THE QUR’AN AND HADITH – REVELATION OF THE GLORIOUS QUR’AN : VISITS OF THE PROPHET (SAW) TO CAVE HIRA"}, {"id": "objective>IRK>2011>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the importance of the first revelation was the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">description of the Arabian peninsula to the Prophet (SAW)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dissemination of knowledge</div>", "<div style=\"font-family:Cambria;font-size:17px;\">explanation of knowledge</div>", "<div style=\"font-family:Cambria;font-size:17px;\">description of the steps of acquiring knowledge</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One of the importance of the first revelation was the dissemination of knowledge. The first revelation marked the beginning of the prophethood of Muhammad and the start of the spread of Islam, which brought a new set of knowledge and teachings to the people.</div>", "topic": "THE QUR’AN AND HADITH – REVELATION OF THE GLORIOUS QUR’AN : HIS REACTION TO THE FIRST REVELATION AND ITS IMPORTANCE"}, {"id": "objective>IRK>2011>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The gradual spiritual and moral development of Muslims was the wisdom behind the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">compilation of the Glorious Qur'an</div>", "<div style=\"font-family:Cambria;font-size:17px;\">standardization of the Glorious Qur'an</div>", "<div style=\"font-family:Cambria;font-size:17px;\">preservation of the Glorious Qur'an</div>", "<div style=\"font-family:Cambria;font-size:17px;\">piecemeal revelation of the Glorious Qur'an</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The wisdom behind the gradual spiritual and moral development of Muslims was the piecemeal revelation of the Glorious Qur'an. The Qur'an was not revealed all at once but over a period of 23 years, allowing the Muslims to gradually understand and implement its teachings in their lives.</div>", "topic": "THE QUR'AN AND HADITH-REVELATION OF THE GLORIOUS QUR'AN : PIECEMEAL REVELATION"}, {"id": "objective>IRK>2011>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The verse above is in relation to the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">standardization of the Glorious Qur'an</div>", "<div style=\"font-family:Cambria;font-size:17px;\">preservation of the Glorious Qur'an</div>", "<div style=\"font-family:Cambria;font-size:17px;\">compilation of the Glorious Qur'an</div>", "<div style=\"font-family:Cambria;font-size:17px;\">arrangement of the Glorious Qur'an</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Preservation of the Quran is quaranteed by Allah because it was revealed from Him. Q1519</div>", "topic": "PRESERVATION OF THE GLORIOUS QUR’AN : COMPLETE ARRANGEMENT"}, {"id": "objective>IRK>2011>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The battle that served as a pointer to the compilation of the Glorious Qur'an was fought at</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Khandaq</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Uhud</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tabak</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Yamamah</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Many Muslims (Qurau) memorizers of the Quran had fallen down at the battle field (yamnmah) in 633. As a result of this, Umar brin khatab suggested to the caliph AbuBakr that Quran should be compiled. </div>", "topic": "THE LIFE OF PROPHET MUHAMMAD (SAW) : THE BATTLES OF BADR, UHUD AND KHANDAQ: CAUSES AND EFFECTS"}, {"id": "objective>IRK>2011>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The committee that standardized the Glorious Qur'an is made up of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">six people</div>", "<div style=\"font-family:Cambria;font-size:17px;\">five people</div>", "<div style=\"font-family:Cambria;font-size:17px;\">four people</div>", "<div style=\"font-family:Cambria;font-size:17px;\">three people</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Uthmah bin Affan appointed a four-man committee for standardization of the Quran. The committee was headed by Zaid bin Thabit. Other members are Abdullah bin Zubari, Sad bin Al-As and Abdu-Ralman bin Harith.</div>", "topic": "PRESERVATION OF THE GLORIOUS QUR’AN : RECORDING, COMPILATION AND STANDARDIZATION OF THE GLORIOUS QUR’AN"}, {"id": "objective>IRK>2011>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A characteristic common to Makkan chapters is that, they</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">are long</div>", "<div style=\"font-family:Cambria;font-size:17px;\">address the people of the Book</div>", "<div style=\"font-family:Cambria;font-size:17px;\">contain a lot of oaths</div>", "<div style=\"font-family:Cambria;font-size:17px;\">make references to battles</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A characteristic common to Makkan chapters is that they contain a lot of oaths. The Makkan chapters are the chapters of the Qur'an that were revealed while the Prophet Muhammad was in Makkah. These chapters often contain oaths and emphasize the oneness of God, the resurrection, and the judgment day.</div>", "topic": "PRESERVATION OF THE GLORIOUS QUR’AN : DIFFERENCES BETWEEN MAKKAH AND MADINAN SUWAR"}, {"id": "objective>IRK>2011>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The victory of the Roman Empire over the Persian Empire after the Persians had defeated the Romans as stated in the Glorious Qur'an (Q. 30: 2-3) is an evidence of the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">beauty of the words of the Glorious Qur'an</div>", "<div style=\"font-family:Cambria;font-size:17px;\">historical nature of the Glorious Qur'an</div>", "<div style=\"font-family:Cambria;font-size:17px;\">simplicity of the wordings of the Glorious Qur'an</div>", "<div style=\"font-family:Cambria;font-size:17px;\">authenticity of the Glorious Qur'an</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The victory of the Roman Empire over the Persian Empire after the Persians had defeated the Romans as stated in the Glorious Qur'an (Q. 30: 2-3) is an evidence of the authenticity of the Glorious Qur'an. This event was predicted in the Qur'an before it happened, which proves the authenticity of the Qur'an.</div>", "topic": "PROOF OF THE DIVINE AUTHENTICITY OF THE GLORIOUS QUR'AN : UNIQUENESS OF THE GLORIOUS QUR'AN"}, {"id": "objective>IRK>2011>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Qur'an is different from other revealed Books because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it is a prayer book only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">barren women can be helped through it</div>", "<div style=\"font-family:Cambria;font-size:17px;\">both spiritual, moral and social values are found in it</div>", "<div style=\"font-family:Cambria;font-size:17px;\">one can use it for protection only</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Qur'an is different from other revealed Books because both spiritual, moral and social values are found in it. The Qur'an is a comprehensive guide for all aspects of life, including spiritual, moral, and social aspects.</div>", "topic": "IMPORTANCE OF THE GLORIOUS QUR’AN : AS SOURCE OF GUIDANCE IN SPIRITUAL, MORAL, ECONOMIC, POLITICAL AND SOCIO-CULTURAL MATTERS."}, {"id": "objective>IRK>2011>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Prophet Muhammad (SAW) did not hand-over the Glorious Qur'an to his companions in an arranged form and in a single written volume because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">he did not want only the Quraish to inherit the book</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the revelation did not come in one piece but at intervals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">many tribes would want to take over its distribution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there was no need for it</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Prophet Muhammad (SAW) did not hand-over the Glorious Qur'an to his companions in an arranged form and in a single written volume because the revelation did not come in one piece but at intervals. The Qur'an was revealed over a period of 23 years, and it was not compiled into a single book during the lifetime of the Prophet.</div>", "topic": "PRESERVATION OF THE GLORIOUS QUR’AN : RECORDING, COMPILATION AND STANDARDIZATION OF THE GLORIOUS QUR’AN"}, {"id": "objective>IRK>2011>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The correct meaning of tafsir is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">detailed explanation and commentary of the Glorious Qur'an</div>", "<div style=\"font-family:Cambria;font-size:17px;\">scientific application of the contents of the Glorious Qur'an to human life</div>", "<div style=\"font-family:Cambria;font-size:17px;\">true reflections on the contents of the Glorious Qur'an</div>", "<div style=\"font-family:Cambria;font-size:17px;\">practical application of the contents of the Glorious Qur'an</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Tafsir is the Arabic word for exegesis, usually of the Qur'an. An author of a tafsir is a mufassir. Tafsir involves explaining, interpreting, expounding, and elucidating the meanings of the Qur'anic verses. Therefore, the correct meaning of tafsir is the detailed explanation and commentary of the Glorious Qur'an.</div>", "topic": "TAFSIR : IMPORTANCE AND TYPES OF TAFSIR"}, {"id": "objective>IRK>2011>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Tajwid as one of the science of the Glorious Qur'an is important because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it allows for the understanding of history of the Glorious Qur'an</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it provides the basis for the deeper understanding of the Glorious Qur'an</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it provides the knowledge of correct pronounciation and recitation of the Glorious Qur'an</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it increases the ability to recite and communicate in Arabic</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Tajwid is a term in Arabic that means to beautify or improve. In the context of the Qur'an, it refers to the rules governing pronunciation during recitation of the Qur'an. Therefore, Tajwid as one of the science of the Glorious Qur'an is important because it provides the knowledge of correct pronunciation and recitation of the Glorious Qur'an.</div>", "topic": "STUDY OF THE ARABIC TEXT OF THE FOLLOWING SUWAR/AYATS WITH TAJWID : AL-FATIHAH"}, {"id": "objective>IRK>2011>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the rule of Tajwid, the portion of the verse underlined above applies to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tarqiq</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tanwin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tafkhim</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tashdid</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Tafkhim Rau. This occur when letter Rau has Dummah.</div>", "topic": "STUDY OF THE ARABIC TEXT OF THE FOLLOWING SUWAR/AYATS WITH TAJWID : AL-MASAD ((Q.111)"}, {"id": "objective>IRK>2011>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The only Surah in the Glorious Qur'an which must be recited in every obligatory prayer is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">al-Baqarah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">al-Alaq</div>", "<div style=\"font-family:Cambria;font-size:17px;\">al-Fatihah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">al-Ikhla's</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Surah Al-Fatihah is the first chapter (Surah) of the Qur'an. Its seven verses (ayat) are a prayer for the guidance, lordship, and mercy of Allah. This chapter has an essential role in Islamic prayer (Salat). The primary literal meaning of the expression 'al-Fatihah' is 'The Opener,' which could refer to this Surah being 'the opener of the Book' (Fatihat al-kitab), to its being the first Surah recited in full in every prayer cycle (rakʿah), or to the manner in which it serves as an opening for many functions in everyday Islamic life. Therefore, the only Surah in the Glorious Qur'an which must be recited in every obligatory prayer is al-Fatihah.</div>", "topic": "STUDY OF THE ARABIC TEXT OF THE FOLLOWING SUWAR/AYATS WITH TAJWID : AL-FATIHAH"}, {"id": "objective>IRK>2011>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The expression <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The verse above in surah al-Lahab means</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">no profit to him from all his power and business</div>", "<div style=\"font-family:Cambria;font-size:17px;\">no profit to him from all his military and economic powers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">no profit to him from all his wealth and gains</div>", "<div style=\"font-family:Cambria;font-size:17px;\">no profit to him from all his property and children</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">His wealth will not benefit him, nor what he has earned.</div>", "topic": "STUDY OF THE ARABIC TEXT OF THE FOLLOWING SUWAR/AYATS WITH TAJWID : AL-MASAD ((Q.111)"}, {"id": "objective>IRK>2011>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Q 16. One important lesson taught in Suratul Kawthar is that Muslims should</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">always fulfil their promises</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protect themselves when the need arises</div>", "<div style=\"font-family:Cambria;font-size:17px;\">accept whatever calamity that befall them</div>", "<div style=\"font-family:Cambria;font-size:17px;\">worship Allah and sacrifice</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Surat Al-Kawthar is the 108th chapter of the Quran. There are several different interpretations of the meaning of the word 'Kawthar,' but a commonly accepted one is that it means 'a river in paradise.' The Surah mentions that the Prophet Muhammad has been given the river by God. The Surah concludes with the command to pray and sacrifice to God alone. Therefore, one important lesson taught in Suratul Kawthar is that Muslims should worship Allah and sacrifice.</div>", "topic": "STUDY OF THE ARABIC TEXT OF THE FOLLOWING SUWAR/AYATS WITH TAJWID : AL -KAWTHAR"}, {"id": "objective>IRK>2011>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Suratul Maun discusses the privilege to be enjoyed by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">givers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">travelers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the wealthy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the needy</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Surat Al-Ma'un is the 107th chapter of the Quran. The Surah criticizes those who are heedless of their prayers, who want to be seen praying, who deny aid to the needy. Therefore, Suratul Maun discusses the privilege to be enjoyed by the needy.</div>", "topic": "STUDY OF THE ARABIC TEXT OF THE FOLLOWING SUWAR/AYATS WITH TAJWID : AL -MAUN"}, {"id": "objective>IRK>2011>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The eagerness and zeal of Muslim warriors to fight in the cause of Allah is one of the major theme of Surah</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">al-Qariyah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">al-Adiyah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">al-Asr</div>", "<div style=\"font-family:Cambria;font-size:17px;\">al-Humazah</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Surah al-Adiyah is known for its emphasis on the zeal and eagerness of Muslim warriors to fight in the cause of Allah. The Surah describes the horses used in battle, their eagerness, and their loyalty to their masters, which is used as a metaphor for the zeal of the Muslim warriors.</div>", "topic": "STUDY OF THE ARABIC TEXT OF THE FOLLOWING SUWAR/AYATS WITH TAJWID : AL -ADIYAT"}, {"id": "objective>IRK>2011>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The allegorical and the ambiguous verses of the Glorious Qur'an are understood through the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ijtihad of Muslim Scholars</div>", "<div style=\"font-family:Cambria;font-size:17px;\">qiyas of Muslim jurists</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tadabbur in the Glorious Qur'an</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tafsir of the Glorious Qur'an</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The allegorical and ambiguous verses of the Glorious Qur'an are understood through the tafsir of the Glorious Qur'an. Tafsir is the Arabic word for exegesis, usually of the Qur'an. An author of a tafsir is a mufassir. Tafsir involves explaining, interpreting, expounding, and elucidating the meanings of the Qur'anic verses.</div>", "topic": "TAFSIR : IMPORTANCE AND TYPES OF TAFSIR"}, {"id": "objective>IRK>2011>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Hadith 3 of an-Nawawias collection shows that Islam is built upon</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">believe in Allah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">five pillars</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fast of Ramadan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">articles of faith</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hadith 3 of an-Nawawi's collection states that Islam is built upon five pillars. These pillars are the declaration of faith (shahada), prayer (salat), almsgiving (zakat), fasting during Ramadan (sawm), and pilgrimage to Mecca (hajj).</div>", "topic": "HADITH : THE STUDY OF THE ARABIC TEXTS OF THE FOLLOWING AHADITH FROMAN-NAWAWI’S COLLECTION: 1,3,5,6,7,9,10,11,12,13,15,16, 18,19,21,22,25,27,34, AND 41"}, {"id": "objective>IRK>2011>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The teaching in the 10th Hadith of an-Nawawi is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Allah accepts prayers from Muslims only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">only credible people shall be elected leaders</div>", "<div style=\"font-family:Cambria;font-size:17px;\">abstinance from forbidden things is prelude to accepting prayers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">abstinance from misconduct by ladies makes them more attractive to men</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The teaching in the 10th Hadith of an-Nawawi is that abstaining from forbidden things is a prelude to accepting prayers. This Hadith emphasizes the importance of avoiding haram (forbidden) actions and behaviors in order to have one's prayers accepted by Allah.</div>", "topic": "HADITH : THE STUDY OF THE ARABIC TEXTS OF THE FOLLOWING AHADITH FROMAN-NAWAWI’S COLLECTION: 1,3,5,6,7,9,10,11,12,13,15,16, 18,19,21,22,25,27,34, AND 41"}, {"id": "objective>IRK>2011>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>Do not get angry</strong> <br/> This tradition from the 16th Hadith of annawawi has been repeated by the Prophet (SAW)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">once</div>", "<div style=\"font-family:Cambria;font-size:17px;\">twice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">thrice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">many times</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hadith Qudsiy is a direct inspiration from Allah to the prophet with any intermediary. It usually conatins some statement like, \"Oh my servant\" or \"O son of Adam\". </div>", "topic": "HADITH : THE STUDY OF THE ARABIC TEXTS OF THE FOLLOWING AHADITH FROMAN-NAWAWI’S COLLECTION: 1,3,5,6,7,9,10,11,12,13,15,16, 18,19,21,22,25,27,34, AND 41"}, {"id": "objective>IRK>2011>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What differentiates Hadith Qudsi from Hadith Nabawi is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">place and manner of application</div>", "<div style=\"font-family:Cambria;font-size:17px;\">condition under which the two are narrated</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wording and teaching intended</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chain and reliability of the narrator</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hadith Qudsi and Hadith Nabawi are both sayings of Prophet Muhammad. The difference lies in the fact that Hadith Qudsi are the words of Allah as revealed to Muhammad but not part of the Quran, while Hadith Nabawi are Muhammad's own words. Therefore, the difference is in the 'wording and teaching intended'.</div>", "topic": "HADITH : AUTHENTICATION OF HADITH"}, {"id": "objective>IRK>2011>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the peculiarities of Sahih Bukhari is that hadith are sorted according to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">topics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chapters</div>", "<div style=\"font-family:Cambria;font-size:17px;\">records</div>", "<div style=\"font-family:Cambria;font-size:17px;\">biographies</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One of the peculiarities of Sahih Bukhari is that hadith are sorted according to chapters.</div>", "topic": "HADITH : HISTORY OF HADITH LITERATURE -COLLECTION OF HADITH FROM THE TIME OF THE PROPHET-SAW TO THE PERIOD OF THE SIX AUTHENTIC COLLECTORS OF HADITH"}, {"id": "objective>IRK>2011>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the two compilers of Hadith that deals with legal traditions of permissions and prohibitions is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Abu Daud</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bukhari</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ibn Maja</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Muslim</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Abu Daud is one of the compilers of Hadith that deals with legal traditions of permissions and prohibitions. His collection, Sunan Abu Dawood, is one of the six canonical collections of Hadith and contains many Hadiths related to legal rulings.</div>", "topic": "HADITH : THE SIX SOUND COLLECTORS OF HADITH – BIOGRAPHIES AND THEIR WORKS."}, {"id": "objective>IRK>2011>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the moral lessons in Q.17:23 apart from obedience to parents is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">resilience</div>", "<div style=\"font-family:Cambria;font-size:17px;\">repentance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">perseverance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">honesty</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Qur'an 17:23: <br/> And your Lord has decreed that you not worship except Him, and to parents, good treatment. If one or both of them reach old age [while] with you, say not to them [so much as], \"uff,\" and do not repel them but speak to them a noble word.</div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR'AN AND HADITH : GOODNESS TO PARENTS"}, {"id": "objective>IRK>2011>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Jews were admonished to avoid mixing truth with falsehood in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Q.2:285</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Q.2:177</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Q.2:45</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Q.2:42</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Q.2:42, the Jews were admonished to avoid mixing truth with falsehood. This verse is a part of Al-Baqarah, the second chapter of the Quran, which addresses the Children of Israel and criticizes their hypocrisy.</div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR'AN AND HADITH : HONESTY"}, {"id": "objective>IRK>2011>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Islam encourages every Muslim to seek a lawful livelihood through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">equitable distribution of wealth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dignity of labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">family inheritance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shared responsibility</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Islam encourages every Muslim to seek a lawful livelihood through the dignity of labour. This is because Islam places a high value on work and productive effort. The concept of 'dignity of labour' means that all types of jobs are respected equally, and no occupation is considered superior or inferior.</div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR’AN AND HADITH : DIGNITY OF LABOUR (Q.62:10) (Q.78:11) HADITH FROM BUKHARI AND IBNMAJAH: “THAT ONE OF YOU TAKES HIS ROPE…….” “NEVER HAS ANYONE OF YOU EATEN…..”."}, {"id": "objective>IRK>2011>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Islam as a monotheistic religion expects that every faithful follower should</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">not tell lies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">serve Allah without associates</div>", "<div style=\"font-family:Cambria;font-size:17px;\">praise the Prophets as enjoined by Allah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">perform Salat</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Islam, being a monotheistic religion, expects every faithful follower to serve Allah without associates. This is the fundamental belief in Islam known as Tawhid, which asserts that Allah is One (indivisible) and the sole creator of the universe.</div>", "topic": "TAWHID AND FIQH : FAITH"}, {"id": "objective>IRK>2011>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Seeking assistance from the fortune tellers is forbidden because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it gives one an insight of what tomorrow holds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it creates animosity amongst people</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it leads to ascribing absolute power to a fellow being</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it's proceed is unlawful</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Seeking assistance from fortune tellers is forbidden in Islam because it leads to ascribing absolute power to a fellow being. This is considered a form of shirk (polytheism) as it attributes to humans powers that belong only to Allah, such as the knowledge of the unseen and the future.</div>", "topic": "TAWHID AND FIQH : SHIRK"}, {"id": "objective>IRK>2011>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">It is shirk in Islam to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sing religious song</div>", "<div style=\"font-family:Cambria;font-size:17px;\">undergo plastic surgery</div>", "<div style=\"font-family:Cambria;font-size:17px;\">masquerade</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is shirk in Islam to masquerade or imitate false deities.</div>", "topic": "TAWHID AND FIQH : SHIRK"}, {"id": "objective>IRK>2011>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Suhf was revealed to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">prophet Haruna (AS)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prophet Ilyas (AS)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prophet Ibrahim (AS)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prophet Muhammd (SAW)</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Suhf was revealed to Prophet Ibrahim (AS). Suhf, in Islamic tradition, refers to the scriptures that were given to Prophet Ibrahim (AS). These scriptures are considered as one of the four revealed books in Islam.</div>", "topic": "ARTICLE OF FAITH : HIS BOOKS"}, {"id": "objective>IRK>2011>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In Islam, the articles of Iman are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">six</div>", "<div style=\"font-family:Cambria;font-size:17px;\">five</div>", "<div style=\"font-family:Cambria;font-size:17px;\">four</div>", "<div style=\"font-family:Cambria;font-size:17px;\">three</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Islam, the articles of Iman (faith) are six. They are belief in Allah, His angels, His books, His messengers, the Day of Judgment, and divine predestination.</div>", "topic": "ARTICLE OF FAITH : BELIEF IN ALLAH"}, {"id": "objective>IRK>2011>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The presentation of Sermon is an obligation on the Imam when leading</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">all the prayers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">funeral prayers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Friday prayers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">every prayer on Friday</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Islam, the presentation of a sermon (Khutbah) is an obligation on the Imam when leading Friday prayers (Jumu'ah). The sermon is a significant part of the Friday prayer service and is meant to provide spiritual guidance and reminders to the congregation.</div>", "topic": "IBADAT AND THEIR TYPES : SALAH"}, {"id": "objective>IRK>2011>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the conditions that make prayer obligatory on believers is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">social status</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reciting the Qur'an with proper Tajweed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">following pious Imam</div>", "<div style=\"font-family:Cambria;font-size:17px;\">attainment of maturity</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One of the conditions that make prayer (Salah) obligatory on believers in Islam is the attainment of maturity (puberty). Other conditions include being of sound mind and being free from any state of ritual impurity.</div>", "topic": "IBADAT AND THEIR TYPES : SALAH"}, {"id": "objective>IRK>2011>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The supreragatory fasting of Ashura is observed on the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8th of al-muharram</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9th of al-Muharram</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10th of al-Muharram</div>", "<div style=\"font-family:Cambria;font-size:17px;\">11th of al-Muharram</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The supererogatory fasting of Ashura is observed on the 10th of Muharram in the Islamic calendar. Ashura marks the day that Moses and the Israelites were saved from Pharaoh by God creating a path in the Sea, and is considered a day of fasting for Muslims.</div>", "topic": "IBADAT AND THEIR TYPES : SAWM"}, {"id": "objective>IRK>2011>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ayyam at-tashriq are the days of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">buying and selling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">visits and caring</div>", "<div style=\"font-family:Cambria;font-size:17px;\">singing and dancing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">eating and drinking</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ayyamu - Tashrig is the 3 days after Eidul Adha in which muslims animal are also permitted to slaughter animal if they have not done it on the Eid - day.</div>", "topic": "IBADAT AND THEIR TYPES : HAJJ"}, {"id": "objective>IRK>2011>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The minimum number of witnesses in an Islamic marriage is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">four males</div>", "<div style=\"font-family:Cambria;font-size:17px;\">three males</div>", "<div style=\"font-family:Cambria;font-size:17px;\">two males</div>", "<div style=\"font-family:Cambria;font-size:17px;\">one male</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In an Islamic marriage, the minimum number of witnesses required is two males. This is based on the Hadith of the Prophet Muhammad (PBUH) where he said, 'No marriage contract can be concluded without the presence of two just men.'</div>", "topic": "FAMILY MATTERS : MARRIAGE"}, {"id": "objective>IRK>2011>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The term, Shari'ah refers to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a path</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wisdom</div>", "<div style=\"font-family:Cambria;font-size:17px;\">passion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an idea</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The term Shari'ah in Islam refers to 'a path'. It is the moral and legal code that governs the lives of Muslims. It covers various aspects of life including daily routines, familial and religious obligations, and financial dealings.</div>", "topic": "TAWHID AND FIQH : FAITH"}, {"id": "objective>IRK>2011>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the scholars reported to have been imprisoned by his non-compromising stance was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Shafi'i</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Abu-Hanifah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hambali</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Maliki B. Anas</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Abu-Hanifah was one of the scholars who was reported to have been imprisoned due to his non-compromising stance. He was a renowned Islamic jurist and the founder of the Hanafi school of thought, one of the four major Sunni Islamic schools of jurisprudence.</div>", "topic": "CONTRIBUTIONS OF ISLAM TO EDUCATION : THE LIVES AND CONTRIBUTIONS OF IBN SINA, AL-GHAZALI, IBN RUSHDI, AR-RAZIO AND IBN KHALDUN TO EDUCATION."}, {"id": "objective>IRK>2011>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The entrenchment of an Islamic economic system is aimed at</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">controlling the world funds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">restricting the unlawful acquisition of wealth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">restricting men to particular occupations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">promoting equitable distribution of wealth</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The entrenchment of an Islamic economic system is aimed at promoting equitable distribution of wealth. Islam encourages the sharing of wealth and discourages hoarding, exploitation and fraud. It promotes business ethics, fairness and justice in the economic sphere.</div>", "topic": "ISLAMIC ECONOMIC SYSTEM : ISLAMIC ATTITUDE TO RIBA HADITH 6TH OF AN-NAWAWI"}, {"id": "objective>IRK>2011>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the major consequences of riba is that, it makes people</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">wealthy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lazy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">smart</div>", "<div style=\"font-family:Cambria;font-size:17px;\">parasitic</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It makes people lazy and neglectful of their real duties.</div>", "topic": "ISLAMIC ECONOMIC SYSTEM : ISLAMIC ATTITUDE TO RIBA HADITH 6TH OF AN-NAWAWI"}, {"id": "objective>IRK>2011>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Mas'uliyyah as a principle of the the Islamic political system is a measure to check</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">indiscipline</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rigging</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nepotism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">misappropriation</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">\"Masuliyyah means a mechanism based on which public officers/affairs are checked with a view to preventing them from misappropriating the resources put in their care.</div>", "topic": "ISLAMIC HISTORY AND CIVILIZATION - PRE-ISLAMIC ARABIA JAHILIYYAH : ISLAMIC REFORMS"}, {"id": "objective>IRK>2011>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Allah commands Muslims to observe and fulfil agreements with the non-Muslims, if the later do not</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">infringe on the right of women</div>", "<div style=\"font-family:Cambria;font-size:17px;\">observe the five daily prayers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">change the language employed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">violate the terms of the agreement</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the Quran, Allah commands Muslims to honor their agreements and treaties with non-Muslims, as long as the latter do not violate the terms of the agreement. This is based on the principle of justice and fairness in Islam, which extends to all individuals, regardless of their religious beliefs.</div>", "topic": "TAWHID AND FIQH : FAITH"}, {"id": "objective>IRK>2011>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">During the Jihiliyya era, the Ka'aba was the centre of poetic contest at the annual festival called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ijaz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ukaz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">manat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ushrah</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During the Jahiliyya era, which refers to the period of ignorance before the advent of Islam, the Ka'aba was the center of a poetic contest at an annual festival called Ukaz. This festival was a significant cultural event in pre-Islamic Arabia, where poets from different tribes would come to recite their verses.</div>", "topic": "ISLAMIC HISTORY AND CIVILIZATION - PRE-ISLAMIC ARABIA JAHILIYYAH : JAHILIYYAH PRACTICES: IDOL WORSHIP, INFANTICIDE, POLYANDRY, GAMBLING, USURY, ETC."}, {"id": "objective>IRK>2011>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In Pre-Islamic Arabia, the Arabs killed their daughters because they</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">were the weaker sex</div>", "<div style=\"font-family:Cambria;font-size:17px;\">were afraid of incest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">feared the females would outnumber males</div>", "<div style=\"font-family:Cambria;font-size:17px;\">did not participate in wars</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is because they did not join the battles alongside others.</div>", "topic": "ISLAMIC HISTORY AND CIVILIZATION - PRE-ISLAMIC ARABIA JAHILIYYAH : JAHILIYYAH PRACTICES: IDOL WORSHIP, INFANTICIDE, POLYANDRY, GAMBLING, USURY, ETC."}, {"id": "objective>IRK>2011>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The first person who recognized signs of Prophethood on Muhammad (SAW) was a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Christian Monk</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Jewish Rabbi</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Buddhist Monk</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Soothsayer</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A christian monk called Bakhirah saw the sign of prophethood in prophet Muhammed in his first journey to syria with his uncle Abu talib. The monk told his uncle to take good care of him. </div>", "topic": "THE LIFE OF PROPHET MUHAMMAD (SAW) : HIS CALL TO PROPHETHOOD"}, {"id": "objective>IRK>2011>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Members of the Prophet's family that embraced Islam the first day did so, on the basis of his</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">truthfulness and uprightness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wealth and influence</div>", "<div style=\"font-family:Cambria;font-size:17px;\">love for them</div>", "<div style=\"font-family:Cambria;font-size:17px;\">family relation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The members of Prophet Muhammad's family who embraced Islam on the first day did so because of his reputation for truthfulness and uprightness, not because of his wealth, influence, love for them, or family relation.</div>", "topic": "THE LIFE OF PROPHET MUHAMMAD (SAW) : HIS CALL TO PROPHETHOOD"}, {"id": "objective>IRK>2011>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The teachings of Uthman B. Fodio are remembered today as it relates to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">idol worshiping</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marrying more than four wives</div>", "<div style=\"font-family:Cambria;font-size:17px;\">all form of syncreticism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">taxing of farm produce</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Uthman B. Fodio, a religious teacher, reformer, and founder of the Sokoto Caliphate, is remembered today for his teachings against all forms of syncretism, which is the combination of different forms of belief or practice.</div>", "topic": "THE IMPACT OF ISLAM IN WEST AFRICA : THE INFLUENCE OF ISLAM ON THE SOCIO-POLITICAL LIFE OF SOME WEST AFRICAN EMPIRES: GHANA, MALI, SONGHAI AND BORNO"}, {"id": "objective>IRK>2011>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The ruler who instituted Friday prayers in Mali was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mansa Musa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mansa Suleiman</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mansa Ule</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mansa Abubakar</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A man Musa was a prominent ruler in Mali who contributed significantly to the development of islam in West Africa.</div>", "topic": "THE IMPACT OF ISLAM IN WEST AFRICA : THE INFLUENCE OF ISLAM ON THE SOCIO-POLITICAL LIFE OF SOME WEST AFRICAN EMPIRES: GHANA, MALI, SONGHAI AND BORNO"}];
